tmCustomCss:
/* ==========================================
淡淡的就会顺顺的 · 线下经典主题 (用户气泡篇)
========================================== */
/* 1. 整体底色改成列表同款灰白 */
#this-moment-screen { background: #fafafa !important; }
.tm-bg-overlay { background: #fafafa !important; }
.tm-bg-image { display: none !important; }
/* 2. 气泡变身卡片底座 */
.tm-para-user {
background: #ffffff !important;
border: 1px solid #f2e9eb !important;
border-radius: 16px !important;
padding: 42px 16px 6px 16px !important; /* 顶部留40给爱心 */
margin-bottom: 24px !important;
position: relative !important;
box-shadow: 0 4px 12px rgba(235, 213, 217, 0.15) !important;
}
/* 3. 最顶部的爱心虚线 */
.tm-para-user::before {
content: " ┈┈┈┈ ♥ ┈┈┈┈ ♡ ┈┈┈┈ ♥ ┈┈┈┈" !important;
position: absolute !important;
top: 8px !important;
left: 0 !important;
right: 0 !important;
text-align: center !important;
color: #ebd5d9 !important;
font-size: 13px !important;
letter-spacing: 2px !important;
pointer-events: none !important;
}
/* 4. Header 容器 (锁死高度，给互动栏留空间) */
.tc-header-user {
position: relative !important;
display: block !important;
height: 100px !important; /* 52px头像 + 48px互动栏 */
margin: 0 !important;
padding: 0 !important;
}
/* 5. 头像框 */
.tc-avatar-frame-user {
position: absolute !important;
top: -5px !important;
left: 2px !important;
width: 61px !important;
height: 61px !important;
border-radius: 50% !important;
border: 2.5px solid #e4c4ca !important;
padding: 2px !important;
background: #ffffff !important;
margin: 0 !important;
overflow: visible !important;
}
.tc-avatar-frame-user img { border-radius: 50% !important; }
/* 6. 头像右下角的 √ */
.tc-avatar-frame-user::after {
content: "" !important;
position: absolute !important;
bottom: -2px !important;
right: -2px !important;
width: 14px !important;
height: 14px !important;
background-color: #ebd5d9 !important;
border-radius: 50% !important;
border: 2px solid #fff !important;
z-index: 10 !important;
background-image: url('data:image/svg+xml;utf8,<svg viewBox="0 0 24 24" fill="none" stroke="%23ffffff" stroke-width="4" stroke-linecap="round" stroke-linejoin="round" xmlns="http://www.w3.org/2000/svg"><polyline points="20 6 9 17 4 12"></polyline></svg>') !important;
background-size: 8px !important;
background-repeat: no-repeat !important;
background-position: center !important;
}
/* 7. 名字与 @ */
.tc-avatar-badge-user {
position: absolute !important;
top: 4px !important;
left: 73px !important;
margin: 0 !important;
display: block !important;
color: #5c4b51 !important;
font-size: 15px !important;
font-weight: bold !important;
}
.tc-avatar-badge-user::before { content: "@ " !important; color: #dcb4bb !important; font-weight: normal !important; }
/* 8. 自定义文案 (加浅粉色底板) */
.tc-header-user::before {
content: "Today is a good day ⊹." !important;
position: absolute !important;
top: 26px !important;
left: 72px !important;
color: #D1BCC0 !important;
font-size: 12px !important;
background: rgba(255, 245, 247, 0.54) !important; /* 👈 最后那个 1 就是透明度，改成 0.8 就是半透 */
padding: 4px 10px 7px 6px !important; /* 只留基础的上下左内边距 */
width: 200px !important;
border-radius: 6px !important;
white-space: nowrap !important; /* 防止文字换行 */
}
/* 9. 时间 (上移到名字的高度) */
.tc-header-user::after {
content: "20:19" !important; /* 👈 时间改这里 */
position: absolute !important;
top: 2px !important;
right: 30px !important;
color: #dcb4bb !important;
font-size: 11px !important;
font-weight: bold !important;
opacity: 0.6 !important;
}
/* 10. 正文区域 (强行接管所有行高和间距) */
.tm-body-user {
position: relative !important;
color: #5c4b51 !important;
font-size: 15px !important;
line-height: 1.8 !important; /* 👈 整体行高 */
margin: 0 !important;
padding: 26px 0 0 5px !important;
border-top: 1px dashed rgba(235, 213, 217, 0.8) !important;
}
/* 连带里面的所有子标签一起镇压 */
.tm-body-user * {
line-height: 1.8 !important;
margin-top: 0 !important;
font-size: inherit !important; /* 👈 强迫里面的字跟着外面变 */
margin-bottom: 10px !important; /* 👈 如果有分段，段落之间的微小间距 */
}
/* 11. 互动栏 - Likes (利用 \A 换行，上文字下数字) */
.tm-body-user::before {
content: "Likes   \A 128" !important; /* 👈 点赞数改这里，Likes后面的空格是给图标留位置的，别删 */
white-space: pre !important;
position: absolute !important;
top: -36px !important; /* 坐在虚线上方 */
left: 16px !important;
width: 60px !important;
text-align: center !important;
color: #dcb4bb !important;
font-size: 11px !important;
line-height: 1.3 !important;
background-image: url('data:image/svg+xml;utf8,<svg viewBox="0 0 24 24" fill="%23dcb4bb" xmlns="http://www.w3.org/2000/svg"><path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path></svg>') !important;
background-size: 12px !important;
background-repeat: no-repeat !important;
background-position: right 7px top 2px !important; /* 图标靠右对齐 */
}
/* 12. 互动栏 - Comments */
.tm-body-user::after {
content: "Comments  \A 32" !important; /* 👈 评论数改这里 */
white-space: pre !important;
position: absolute !important;
top: -36px !important;
left: 50% !important;
transform: translateX(-50%) !important; /* 绝对居中 */
width: 80px !important;
text-align: center !important;
color: #dcb4bb !important;
font-size: 11px !important;
line-height: 1.3 !important;
background-image: url('data:image/svg+xml;utf8,<svg viewBox="0 0 24 24" fill="%23dcb4bb" xmlns="http://www.w3.org/2000/svg"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"></path></svg>') !important;
background-size: 12px !important;
background-repeat: no-repeat !important;
background-position: right 0px top 2px !important;
}
/* 13. 互动栏 - Shares (书签旗帜图标) */
.tm-para-user::after {
content: "Shares   \A 120" !important; /* 👈 分享数改这里 */
white-space: pre !important;
position: absolute !important;
top: 107px !important; /* 精准定位在虚线上方 */
right: 32px !important;
width: 70px !important;
text-align: center !important;
color: #dcb4bb !important;
font-size: 11px !important;
line-height: 1.3 !important;
/* 换成了你画的书签/旗帜图标 */
background-image: url('data:image/svg+xml;utf8,<svg viewBox="0 0 24 24" fill="%23dcb4bb" xmlns="http://www.w3.org/2000/svg"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"></path></svg>') !important;
background-size: 11px !important;
background-repeat: no-repeat !important;
background-position: right 8px top 3px !important;
}
/* 14. 正文上方的 ✧ Messages */
.tc-avatar-frame-user::before {
content: "✧ Messages" !important;
position: absolute !important;
top: 108px !important; /* 👈 如果位置偏上或偏下，改这个数字 */
left: 0px !important; /* 和头像左边缘对齐 */
color: #dcb4bb !important;
font-weight: bold !important;
letter-spacing: 1px !important;
white-space: nowrap !important;
font-size: 11px !important;
}
/* ==========================================
顶栏与底栏 (淡淡的就会顺顺的)
========================================== */

/* 15. 顶栏 (毛玻璃 + 茱萸粉图标) */
.tm-header {
background: rgba(255, 253, 253, 0.85) !important;
backdrop-filter: blur(20px) !important;
-webkit-backdrop-filter: blur(20px) !important;
border-bottom: 1px solid #f2e9eb !important;
}
.tm-header-name {
color: #5c4b51 !important;
font-size: 15px !important;
font-weight: bold !important;
}
.tm-btn-icon {
color: #dcb4bb !important; /* 返回、书本、设定图标 */
}
.tm-top-vs {
color: #ebd5d9 !important; /* 中间的乘号 */
}
.tm-header-avatar {
border: 2px solid #e4c4ca !important;
border-radius: 50% !important;
}

/* 16. 底栏输入区 */
.tm-compose {
background: rgba(255, 253, 253, 0.95) !important;
border-top: 1px solid #f2e9eb !important;
backdrop-filter: blur(20px) !important;
-webkit-backdrop-filter: blur(20px) !important;
}
/* 输入框 */
.tm-input {
background: #ffffff !important;
border: 1px solid #ebd5d9 !important;
border-radius: 24px !important;
color: #5c4b51 !important;
}
.tm-input::placeholder {
color: rgba(235, 213, 217, 0.8) !important;
}
/* 发送按钮 */
.tm-send-btn {
color: #ebd5d9 !important; /* 没打字时浅粉色 */
}
.tm-send-btn.ready {
background: #dcb4bb !important; /* 打字后变实心茱萸粉 */
color: #ffffff !important;
border-radius: 50% !important;
}
/* 工具栏小按钮 (重投、白噪音等) */
.tm-regen-btn {
color: #dcb4bb !important;
}
.tm-regen-btn.active {
background: #fff5f7 !important;
color: #dcb4bb !important;
border-color: #ebd5d9 !important;
}

/* ==========================================
细节微调：发送键 / 卡片居中 / 底栏变矮
========================================== */
